%[text] ## `Configure MATLAB:`
restoredefaultpath;    clear;    close all;    clc;    addpath(genpath(fileparts(mfilename('fullpath')))) % In case "Configure" is not available.
Configure
%%
Directory.Data  = string(pwd) + "\Data";%"C:\Users\zacha\ASU Dropbox\Zachary Hendrix\Hand\";
Directory.Files = dir(fullfile(Directory.Data, 'MutualInformation(nSegments=*).mat'))  ;

if       isempty(Directory.Files);    error("No Directory.Files Matching MutualInformation(nSegments=*.mat) Found in %s", Directory.Data);    end
nFiles   = numel(Directory.Files);

L        = nan(nFiles,1); % L: Number of Segments
Ntotal   = nan(nFiles,1); % N : Observation Budget
Nprime   = nan(nFiles,1); % N': Observations per Segment
I_mean   = nan(nFiles,3); % Columns: Long, LongRestart, Many
I_se     = nan(nFiles,3);
JS_mean  = nan(nFiles,3); % Columns: w vs wtilde, w vs u, wtilde vs u
JS_se    = nan(nFiles,3);

% Store Seed-Level Arrays for Panel B.
InfoLong        = cell(nFiles,1);
InfoLongRestart = cell(nFiles,1);
InfoMany        = cell(nFiles,1);

for k                    = 1 : nFiles
    fileName             = fullfile(Directory.Files(k).folder, Directory.Files(k).name);
    S                    = load(fileName)                                              ;

    L              (k)   = double(S.Acq.nSegments)  ;
    Ntotal         (k)   = double(S.Acq.Long_nTimes);
    Nprime         (k)   = double(S.Acq.Many_nTimes);

    I_mean         (k,:) = [double(S.MI.Long.mean), double(S.MI.LongRestart.mean), double(S.MI.Many.mean)];
    I_se           (k,:) = [double(S.MI.Long.se), double(S.MI.LongRestart.se), double(S.MI.Many.se)]      ;

    JS_mean        (k,:) = [double(S.MI.JS.Long_vs_LongRestart.mean), double(S.MI.JS.Long_vs_Many.mean), double(S.MI.JS.LongRestart_vs_Many.mean)];
    JS_se          (k,:) = [double(S.MI.JS.Long_vs_LongRestart.se), double(S.MI.JS.Long_vs_Many.se), double(S.MI.JS.LongRestart_vs_Many.se)]      ;

    InfoLong       {k}   = double(S.Store.Info.Long.bits(:))       ;
    InfoLongRestart{k}   = double(S.Store.Info.LongRestart.bits(:));
    InfoMany       {k}   = double(S.Store.Info.Many.bits(:))       ;
end

% Sort by Number of Segments            :
[L, Order]      = sort(L)               ;
Ntotal          = Ntotal(Order)         ;
Nprime          = Nprime(Order)         ;
I_mean          = I_mean(Order,:)       ;
I_se            = I_se(Order,:)         ;
JS_mean         = JS_mean(Order,:)      ;
JS_se           = JS_se(Order,:)        ;
InfoLong        = InfoLong(Order)       ;
InfoLongRestart = InfoLongRestart(Order);
InfoMany        = InfoMany(Order)       ;

if max(Ntotal) - min(Ntotal) ~= 0;    warning("Not All Directory.Files Have the Same Fixed Observation Budget N.");    end

% Print Summary Table.
Summary = table(L, Nprime, I_mean(:,1), I_se(:,1), I_mean(:,2), I_se(:,2), I_mean(:,3), I_se(:,3), JS_mean(:,1), JS_se(:,1), JS_mean(:,2), JS_se(:,2), JS_mean(:,3), JS_se(:,3), 'VariableNames', {'L','Nprime', 'I_w_mean','I_w_se','I_wtilde_mean','I_wtilde_se','I_u_mean','I_u_se', 'J_w_wtilde_mean','J_w_wtilde_se','J_w_u_mean','J_w_u_se','J_wtilde_u_mean','J_wtilde_u_se'});
disp(Summary); %[output:987e6f97]

Color.Long  = [0.780 0.039 0.039]; %[control:colorPicker:66fd]{"position":[15,34]}
Color.Rest  = [0.961 0.467 0.161]; %[control:colorPicker:053c]{"position":[15,34]}
Color.Many  = [0.929 0.694 0.125]; %[control:colorPicker:2f52]{"position":[15,34]}
colors = [Color.Long ; % w
          Color.Rest ; % wtilde
          Color.Many]; % u

Color.J1 = [0.231 0.667 0.196];               %[control:colorPicker:3db9]{"position":[12,31]}
Color.J2 = [0.067 0.443 0.745]; %[control:colorPicker:5d66]{"position":[12,31]}
Color.J3 = [0.522 0.086 0.820]; %[control:colorPicker:6f24]{"position":[12,31]}
colors2 = [Color.Rest; % w
           Color.Many; % wtilde
           Color.J1 ]; % u

LineWidth  = 1.6;
MarkerSize = 6  ;
CapSize    = 8  ;

FontSize(1) = 20;
FontSize(2) = 17;
FontSize(3) = 14;

Figure = figure("Color",'w', "Units",'Inches', "Position",[1 1 11 9]); %[output:050d7fb5]
%Tiles  = tiledlayout(Figure, 3, 1, "TileSpacing",'Compact', "Padding",'Compact');
 Tiles  = tiledlayout(Figure, 3, 1, "TileSpacing",'Compact', "Padding",'Compact'); %[output:050d7fb5]

% Panel (a):
Axes(1) = nexttile(Tiles, 1); hold(Axes(1),"On"); box(Axes(1),"On"); %[output:050d7fb5]
labelsA = {'$\langle I_{\mathbf{\mathit{w}}}\rangle$', '$\langle I_{\widetilde{\mathbf{{w}}} \rangle$', '$\langle I_{\mathbf{u}} \rangle$'};

for j = 1 : 3;    errorbar(Axes(1), L, I_mean(:,j), I_se(:,j), '-o', "Color",colors(j,:), "MarkerFaceColor",colors(j,:), "LineWidth",LineWidth, "MarkerSize",MarkerSize, "CapSize",CapSize);    end %[output:050d7fb5]
set(Axes(1), "XScale",'log', "XTick",L, "XTickLabel", compose('%d', L), "TickLabelInterpreter",'LaTeX', "FontSize",FontSize(3)); %[output:050d7fb5]
xlim(Axes(1), [min(L)/1, max(L)*1]); %[output:050d7fb5]
ylabel(Axes(1), '$\langle{I}\rangle$ [bits]', "Interpreter",'LaTeX'); %[output:050d7fb5]
 title(Axes(1), '(a)', "Interpreter",'LaTeX'); %[output:050d7fb5]
legend(Axes(1), labelsA, "Interpreter",'LaTeX', 'Location','southwest', "Box","Off", 'Orientation','horizontal'); %[output:050d7fb5]
  grid(Axes(1),"On"); %[output:050d7fb5]

%{
% Panel (b):
Axes(2) = nexttile(Tiles, 2); hold(Axes(2),"On"); box(Axes(2),"On");
rng(7);
Delta_mean = nan(numel(L),2);
Delta_ci95 = nan(numel(L),2);

for k = 1 : numel(L)
    dRest = InfoLongRestart{k} - InfoLong{k};
    dMany = InfoMany{k}        - InfoLong{k};

    xRest = L(k) * exp(-0.065 + 0.018*randn(size(dRest)));
    xMany = L(k) * exp( 0.065 + 0.018*randn(size(dMany)));

    scatter(Axes(2), xRest, dRest, 12, colors2(1,:), "Filled", "MarkerFaceAlpha",0.16, "MarkerEdgeAlpha",0.16, "HandleVisibility","Off");
    scatter(Axes(2), xMany, dMany, 12, colors2(1,:), "Filled", "MarkerFaceAlpha",0.16, "MarkerEdgeAlpha",0.16, "HandleVisibility","Off");

    Delta_mean(k,1) = mean(dRest, "omitNaN");
    Delta_mean(k,2) = mean(dMany, "omitNaN");
    Delta_ci95(k,1) = 1.96 * std(dRest, 0, "omitNaN") / sqrt(sum(~isnan(dRest)));
    Delta_ci95(k,2) = 1.96 * std(dMany, 0, "omitNaN") / sqrt(sum(~isnan(dMany)));
end

hB1 = errorbar(Axes(2), L*exp(-0.065), Delta_mean(:,1), Delta_ci95(:,1), '-o', "Color",colors2(1,:), "MarkerFaceColor",colors2(1,:), "LineWidth",LineWidth, "MarkerSize",MarkerSize, "CapSize",CapSize);
hB2 = errorbar(Axes(2), L*exp( 0.065), Delta_mean(:,2), Delta_ci95(:,2), '-o', "Color",colors2(2,:), "MarkerFaceColor",colors2(2,:), "LineWidth",LineWidth, "MarkerSize",MarkerSize, "CapSize",CapSize);
yline(Axes(2), 0, 'k:', "LineWidth",1.1, "HandleVisibility","Off");
set(Axes(2), "XScale",'log', "XTick",L, "XTickLabel", compose('%d', L), "TickLabelInterpreter",'LaTeX', "FontSize",FontSize(3));
xlim(Axes(2), [min(L)/1, max(L)*1]);
ylabel(Axes(2), '$\mathit{\Delta}{{I}}$ Relative to $w$ [bits]', "Interpreter",'LaTeX');
%title(Axes(2), '(b) Information Change Induced by Segmentating or Pooling Data', "Interpreter",'LaTeX');
legend(Axes(2), [hB1 hB2], {'${I}_{\widetilde{\mathbf{w}}}-{I}_{\mathbf{\mathit{w}}}$', '${I}_{\mathbf{u}}-{I}_{\mathbf{\mathit{w}}}$'}, "Interpreter",'LaTeX', 'Location','southwest', "Box","Off", 'Orientation','horizontal');
grid(Axes(2),"On");
%}

% Panel (c):
%Axes(3) = nexttile(Tiles, 3); hold(Axes(3),"On"); box(Axes(3),"On");
 Axes(3) = nexttile(Tiles, 2); hold(Axes(3),"On"); box(Axes(3),"On"); %[output:050d7fb5]

labelsC = {'${J}_{\mathbf{\mathit{w}},\widetilde{\mathbf{w}}}$', '${J}_{\mathbf{\mathit{w}},\mathbf{u}}$', '${J}_{\widetilde{\mathbf{w}},\mathbf{u}}$'};
for j = 1:3
    cErrorBar(j) = errorbar(Axes(3), L, JS_mean(:,j), JS_se(:,j), '-o', "Color",colors2(j,:), "MarkerFaceColor",colors2(j,:), "LineWidth",LineWidth, "MarkerSize",MarkerSize, "CapSize",CapSize); %[output:050d7fb5]
end
set(Axes(3), "XScale",'log', "XTick",L, "XTickLabel", compose('%d', L), "TickLabelInterpreter",'LaTeX', "FontSize",FontSize(3)); %[output:050d7fb5]
xlim(Axes(3), [min(L)/1, max(L)*1]); %[output:050d7fb5]
xlabel(Axes(3), '$L$', "Interpreter",'LaTeX'); %[output:050d7fb5]
ylabel(Axes(3), '${J}$ [bits]', "Interpreter",'LaTeX'); %[output:050d7fb5]
title(Axes(3), '(b)', "Interpreter",'LaTeX'); %[output:050d7fb5]
legend(Axes(3), labelsC, "Interpreter",'LaTeX', 'Location','northwest', "Box","Off", 'Orientation','horizontal'); %[output:050d7fb5]
grid(Axes(3),"On"); %[output:050d7fb5]

drawnow;

if~exist("Lab1",'var');    Lab1 = Axes(3).XLabel.Position;   end
Axes(3).XLabel.Position  = Lab1 + [-0.5,+0.0575,0]; %[output:050d7fb5]

cErrorBar(3).LineStyle = "--"; %[output:050d7fb5]
Axes(3).YTick      = linspace(Axes(3).YLim(1), Axes(3).YLim(2), 3); %[output:050d7fb5]
Axes(3).YTickLabel = Axes(3).YTick                                ; %[output:050d7fb5]

Axes(1).YTick      = [7  7.3  7.6]; %[output:050d7fb5]
Axes(1).YTickLabel = Axes(1).YTick; %[output:050d7fb5]

noAxes = nexttile(Tiles); %[output:050d7fb5]
%%
print("Figure(3)","-dpng","-r350")

